import { useCalendarStore } from '../stores/useCalendarStore';
import { useKanbanStore } from '../stores/useKanbanStore';
import { REMINDER_OPTIONS } from '../services/eventReminders';
import {
  getStandardDateKey,
  getFirstDayOfMonth,
  getDaysInMonth,
  getDaysInPrevMonth,
  isToday,
  isDateBetween,
} from '../utils/dateUtils';
import type { Task, CalendarEvent } from '../types';
import { format, startOfMonth, endOfMonth, startOfWeek, endOfWeek, addDays } from 'date-fns';
import { generateRecurringInstances, expandMultiDayEvent } from '../utils/recurrence';

/**
 * Calendar Widget - React Version
 * Features:
 * - Monthly/Weekly view toggle
 * - Event management
 * - Task date range bars (synced with Kanban)
 * - Fully typed and tested
 */
export const Calendar: React.FC = () => {
  const {
    currentDate,
    viewMode,
    events,
    setViewMode,
    nextPeriod,
    prevPeriod,
    addEvent,
    updateEvent,
    deleteEvent,
    createEventException,
    updateRecurringSeries,
    deleteRecurringSeries,
  } = useCalendarStore();

  const { tasks } = useKanbanStore();

  // Expand recurring and multi-day events for current view
  const expandedEvents = useMemo(() => {
    const result: Record<string, CalendarEvent[]> = {};

    // Determine view date range
    let viewStart: Date;
    let viewEnd: Date;

    if (viewMode === 'monthly') {
      viewStart = startOfMonth(currentDate);
      viewEnd = endOfMonth(currentDate);
    } else if (viewMode === 'weekly') {
      viewStart = startOfWeek(currentDate);
      viewEnd = endOfWeek(currentDate);
    } else {
      // Daily view
      viewStart = currentDate;
      viewEnd = addDays(currentDate, 1);
    }

    // Process all events
    Object.entries(events).forEach(([dateKey, dayEvents]) => {
      dayEvents.forEach((event) => {
        if (event.recurrence) {
          // Generate recurring instances
          const instances = generateRecurringInstances(event, dateKey, viewStart, viewEnd);
          instances.forEach(({ date, event: instanceEvent }) => {
            // Also expand multi-day for each recurring instance
            const multiDayInstances = expandMultiDayEvent(instanceEvent, date);
            multiDayInstances.forEach((multiDayEvent, multiDayDate) => {
              if (!result[multiDayDate]) result[multiDayDate] = [];
              result[multiDayDate].push(multiDayEvent);
            });
          });
        } else {
          // Non-recurring event - check if multi-day
          const multiDayInstances = expandMultiDayEvent(event, dateKey);
          multiDayInstances.forEach((multiDayEvent, multiDayDate) => {
            if (!result[multiDayDate]) result[multiDayDate] = [];
            result[multiDayDate].push(multiDayEvent);
          });
        }
      });
    });

    return result;
  }, [events, currentDate, viewMode]);

  // Modal state
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedDateKey, setSelectedDateKey] = useState('');
  const [newEventTitle, setNewEventTitle] = useState('');
  const [newEventDescription, setNewEventDescription] = useState('');
  const [editingEventId, setEditingEventId] = useState<string | null>(null);
  const [isAllDay, setIsAllDay] = useState(true);
  const [startTime, setStartTime] = useState('09:00');
  const [endTime, setEndTime] = useState('10:00');
  const [eventEndDate, setEventEndDate] = useState<string>(''); // Multi-day end date
  const [recurrenceType, setRecurrenceType] = useState<'none' | 'daily' | 'weekly' | 'monthly'>('none');

  // Recurrence options state
  const [weeklyDays, setWeeklyDays] = useState<number[]>([]);
  const [monthlyDay, setMonthlyDay] = useState<number>(1);
  const [recurrenceEndType, setRecurrenceEndType] = useState<'never' | 'after' | 'until'>('never');
  const [recurrenceEndCount, setRecurrenceEndCount] = useState<number>(10);
  const [recurrenceEndDate, setRecurrenceEndDate] = useState<string>('');

  // Reminder state
  const [eventReminders, setEventReminders] = useState<number[]>([]);

  // Location state
  const [eventLocation, setEventLocation] = useState<string>('');

  // Recurring event dialog state
  const [isRecurringDialogOpen, setIsRecurringDialogOpen] = useState(false);
  const [recurringAction, setRecurringAction] = useState<'edit' | 'delete'>('edit');
  const [pendingRecurringEvent, setPendingRecurringEvent] = useState<CalendarEvent | null>(null);

  const handleDayClick = (dateKey: string) => {
    setSelectedDateKey(dateKey);
    setNewEventTitle('');
    setNewEventDescription('');
    setEditingEventId(null);
    setIsAllDay(true);
    setStartTime('09:00');
    setEndTime('10:00');
    setIsModalOpen(true);
  };

  const handleAddEvent = () => {
    if (newEventTitle.trim()) {
      const eventData: Partial<CalendarEvent> = {
        title: newEventTitle.trim(),
        description: newEventDescription.trim(),
        isAllDay,
        startTime: !isAllDay ? startTime : undefined,
        endTime: !isAllDay ? endTime : undefined,
        endDate: eventEndDate || undefined, // Multi-day end date
        reminders: eventReminders.length > 0 ? eventReminders : undefined,
        location: eventLocation.trim() || undefined,
      };

      // Add recurrence if selected (only for new events)
      if (recurrenceType !== 'none' && !editingEventId) {
        eventData.recurrence = {
          frequency: recurrenceType,
          interval: 1,
          endType: recurrenceEndType,
          endCount: recurrenceEndType === 'after' ? recurrenceEndCount : undefined,
          endDate: recurrenceEndType === 'until' ? recurrenceEndDate : undefined,
        };

        // Add weekly-specific options
        if (recurrenceType === 'weekly' && weeklyDays.length > 0) {
          eventData.recurrence.daysOfWeek = weeklyDays;
        }

        // Add monthly-specific options
        if (recurrenceType === 'monthly') {
          eventData.recurrence.dayOfMonth = monthlyDay;
        }
      }

      if (editingEventId) {
        // Check if editing an exception (this event only) or series (all events)
        if (editingEventId.includes('-exception')) {
          // Create exception for this event only
          const parentId = editingEventId.replace('-exception', '');
          createEventException(selectedDateKey, parentId, eventData);
        } else {
          // Check if this is a recurring series
          const event = dayEvents.find((e) => e.id === editingEventId);
          if (event?.recurrence) {
            // Update entire recurring series
            updateRecurringSeries(editingEventId, eventData);
          } else {
            // Update single event
            updateEvent(selectedDateKey, editingEventId, eventData.title!, eventData.description, eventData);
          }
        }
        setEditingEventId(null);
      } else {
        // Add new event
        addEvent(selectedDateKey, eventData.title!, eventData.description, eventData);
      }
      setNewEventTitle('');
      setNewEventDescription('');
      setIsAllDay(true);
      setStartTime('09:00');
      setEndTime('10:00');
      setEventEndDate('');
      setRecurrenceType('none');
      setWeeklyDays([]);
      setMonthlyDay(1);
      setRecurrenceEndType('never');
      setRecurrenceEndCount(10);
      setRecurrenceEndDate('');
      setEventReminders([]);
      setEventLocation('');
    }
  };

  const handleEditEvent = (event: CalendarEvent) => {
    // Check if this is a recurring event or instance
    const isRecurring = !!event.recurrence || !!event.recurrenceId;

    if (isRecurring) {
      // Show dialog to choose: edit this event or all events
      setPendingRecurringEvent(event);
      setRecurringAction('edit');
      setIsRecurringDialogOpen(true);
    } else {
      // Non-recurring event - edit directly
      setNewEventTitle(event.title);
      setNewEventDescription(event.description || '');
      setIsAllDay(event.isAllDay !== false);
      setStartTime(event.startTime || '09:00');
      setEndTime(event.endTime || '10:00');
      setEventReminders(event.reminders || []);
      setEventLocation(event.location || '');
      setEditingEventId(event.id);
    }
  };

  const handleCancelEdit = () => {
    setNewEventTitle('');
    setNewEventDescription('');
    setIsAllDay(true);
    setStartTime('09:00');
    setEndTime('10:00');
    setEventReminders([]);
    setEventLocation('');
    setEditingEventId(null);
  };

  const handleDeleteEvent = (eventId: string) => {
    // Find the event to check if it's recurring
    const event = dayEvents.find((e) => e.id === eventId);
    if (!event) return;

    const isRecurring = !!event.recurrence || !!event.recurrenceId;

    if (isRecurring) {
      // Show dialog to choose: delete this event or all events
      setPendingRecurringEvent(event);
      setRecurringAction('delete');
      setIsRecurringDialogOpen(true);
    } else {
      // Non-recurring event - delete directly
      deleteEvent(selectedDateKey, eventId);
      if (editingEventId === eventId) {
        handleCancelEdit();
      }
    }
  };

  // Handle editing this event only (create exception)
  const handleEditThisEvent = () => {
    if (!pendingRecurringEvent) return;

    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;

    // Pre-fill form with event data
    setNewEventTitle(pendingRecurringEvent.title);
    setNewEventDescription(pendingRecurringEvent.description || '');
    setIsAllDay(pendingRecurringEvent.isAllDay !== false);
    setStartTime(pendingRecurringEvent.startTime || '09:00');
    setEndTime(pendingRecurringEvent.endTime || '10:00');
    setEditingEventId(`${parentId}-exception`);

    setPendingRecurringEvent(null);
  };

  // Handle editing all events in series
  const handleEditAllEvents = () => {
    if (!pendingRecurringEvent) return;

    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;

    // Pre-fill form with event data
    setNewEventTitle(pendingRecurringEvent.title);
    setNewEventDescription(pendingRecurringEvent.description || '');
    setIsAllDay(pendingRecurringEvent.isAllDay !== false);
    setStartTime(pendingRecurringEvent.startTime || '09:00');
    setEndTime(pendingRecurringEvent.endTime || '10:00');
    setEditingEventId(parentId);

    setPendingRecurringEvent(null);
  };

  // Handle deleting this event only (create exception)
  const handleDeleteThisEvent = () => {
    if (!pendingRecurringEvent) return;

    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;

    // Create exception that marks this instance as deleted
    createEventException(selectedDateKey, parentId, {
      title: pendingRecurringEvent.title,
      description: pendingRecurringEvent.description,
      recurrenceException: true,
      isAllDay: true, // Hidden exception
    });

    setPendingRecurringEvent(null);
  };

  // Handle deleting all events in series
  const handleDeleteAllEvents = () => {
    if (!pendingRecurringEvent) return;

    const parentId = pendingRecurringEvent.recurrenceId || pendingRecurringEvent.id;
    deleteRecurringSeries(parentId);

    if (editingEventId === parentId || editingEventId?.startsWith(`${parentId}-`)) {
      handleCancelEdit();
    }

    setPendingRecurringEvent(null);
  };

  const dayEvents = expandedEvents[selectedDateKey] || [];

  return (
    <Widget id="calendar" title="Calendar" category="Planning" draggable={false}>
      <div className="calendar-widget h-full flex flex-col">
        {/* Calendar Navigation - FROZEN */}
        <div className="flex-shrink-0 px-4 pt-4">
          <div className="calendar-nav flex items-center justify-between mb-4">
          <button
            onClick={prevPeriod}
            className="px-3 py-1 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors"
          >
            ← Prev
          </button>

          <div className="calendar-current-month text-center font-semibold text-text-light-primary dark:text-text-dark-primary">
            {currentDate.toLocaleDateString('en-US', {
              month: 'long',
              year: 'numeric',
            })}
          </div>

          <div className="flex gap-2">
            {/* View Mode Switcher */}
            <div className="flex gap-1 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded p-1">
              <button
                onClick={() => setViewMode('monthly')}
                className={`px-3 py-1 rounded text-sm transition-colors ${
                  viewMode === 'monthly'
                    ? 'bg-accent-blue text-white'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
                }`}
              >
                Month
              </button>
              <button
                onClick={() => setViewMode('weekly')}
                className={`px-3 py-1 rounded text-sm transition-colors ${
                  viewMode === 'weekly'
                    ? 'bg-accent-blue text-white'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
                }`}
              >
                Week
              </button>
              <button
                onClick={() => setViewMode('daily')}
                className={`px-3 py-1 rounded text-sm transition-colors ${
                  viewMode === 'daily'
                    ? 'bg-accent-blue text-white'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
                }`}
              >
                Day
              </button>
              <button
                onClick={() => setViewMode('agenda')}
                className={`px-3 py-1 rounded text-sm transition-colors ${
                  viewMode === 'agenda'
                    ? 'bg-accent-blue text-white'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark'
                }`}
              >
                List
              </button>
            </div>

            {/* Print Button */}
            <button
              onClick={() => window.print()}
              className="p-2 hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated rounded transition-colors no-print"
              title="Print calendar"
            >
              🖨️
            </button>

            <button
              onClick={nextPeriod}
              className="px-3 py-1 bg-accent-blue hover:bg-accent-blue-hover text-white rounded transition-colors"
            >
              Next →
            </button>
          </div>
        </div>
      </div>

      {/* Calendar Grid - SCROLLABLE */}
      <div className="flex-1 overflow-y-auto px-4 pb-4">
          {viewMode === 'monthly' ? (
            <MonthView
              currentDate={currentDate}
              events={expandedEvents}
              tasks={tasks}
              onDayClick={handleDayClick}
            />
          ) : viewMode === 'weekly' ? (
            <WeekView
              currentDate={currentDate}
              events={expandedEvents}
              tasks={tasks}
              onDayClick={handleDayClick}
              onEventClick={(event, dateKey) => {
                setSelectedDateKey(dateKey);
                setNewEventTitle(event.title);
                setNewEventDescription(event.description || '');
                setIsAllDay(event.isAllDay !== false);
                setStartTime(event.startTime || '09:00');
                setEndTime(event.endTime || '10:00');
                setEditingEventId(event.id);
                setIsModalOpen(true);
              }}
              showTimeSlots={true}
            />
          ) : viewMode === 'daily' ? (
            <DayView
              date={currentDate}
              events={expandedEvents[format(currentDate, 'yyyy-MM-dd')] || []}
              onEventClick={(event, dateKey) => {
                setSelectedDateKey(dateKey);
                setNewEventTitle(event.title);
                setNewEventDescription(event.description || '');
                setIsAllDay(event.isAllDay !== false);
                setStartTime(event.startTime || '09:00');
                setEndTime(event.endTime || '10:00');
                setEditingEventId(event.id);
                setIsModalOpen(true);
              }}
              onTimeSlotClick={(hour) => {
                const dateKey = format(currentDate, 'yyyy-MM-dd');
                setSelectedDateKey(dateKey);
                setNewEventTitle('');
                setNewEventDescription('');
                setEditingEventId(null);
                setIsAllDay(false);
                setStartTime(`${hour.toString().padStart(2, '0')}:00`);
                setEndTime(`${(hour + 1).toString().padStart(2, '0')}:00`);
                setIsModalOpen(true);
              }}
            />
          ) : (
            <AgendaView
              events={expandedEvents}
              currentDate={currentDate}
              daysToShow={14}
              onEventClick={(event, dateKey) => {
                setSelectedDateKey(dateKey);
                setNewEventTitle(event.title);
                setNewEventDescription(event.description || '');
                setIsAllDay(event.isAllDay !== false);
                setStartTime(event.startTime || '09:00');
                setEndTime(event.endTime || '10:00');
                setEventReminders(event.reminders || []);
                setEditingEventId(event.id);
                setIsModalOpen(true);
              }}
            />
          )}
        </div>
      </div>

      {/* Event Modal */}
      <Modal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={`Events for ${selectedDateKey}`}
      >
        <div className="space-y-4">
          {/* Existing Events List */}
          {dayEvents.length > 0 && (
            <div className="space-y-2">
              <h4 className="text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary">
                Events ({dayEvents.length})
              </h4>
              {dayEvents.map((event) => (
                <div
                  key={event.id}
                  className={`p-3 rounded-lg transition-all ${
                    editingEventId === event.id
                      ? 'bg-accent-blue/10 dark:bg-accent-blue/20 ring-2 ring-accent-blue'
                      : 'bg-surface-light-elevated dark:bg-surface-dark-elevated'
                  }`}
                >
                  <div className="flex items-start justify-between gap-2">
                    <div className="flex-1 min-w-0">
                      <div className="font-medium text-text-light-primary dark:text-text-dark-primary">{event.title}</div>
                      {event.startTime && (
                        <div className="text-sm text-accent-blue dark:text-accent-blue-hover mt-1">
                          {event.startTime} {event.endTime && `- ${event.endTime}`}
                        </div>
                      )}
                      {event.description && (
                        <div className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
                          {event.description}
                        </div>
                      )}
                    </div>
                    <div className="flex gap-2">
                      <button
                        onClick={() => handleEditEvent(event)}
                        className="px-3 py-1 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors"
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => handleDeleteEvent(event.id)}
                        className="px-3 py-1 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
                      >
                        Delete
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Add/Edit Event Form */}
          <div>
            <label
              htmlFor="new-event-input"
              className="block text-sm font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2"
            >
              {editingEventId ? 'Edit Event' : 'Add New Event'}
            </label>
            <div className="space-y-2">
              <input
                id="new-event-input"
                type="text"
                value={newEventTitle}
                onChange={(e) => setNewEventTitle(e.target.value)}
                placeholder="Enter event title..."
                className="w-full px-4 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                onKeyPress={(e) => {
                  if (e.key === 'Enter' && !e.shiftKey) handleAddEvent();
                }}
              />
              <textarea
                id="new-event-description"
                value={newEventDescription}
                onChange={(e) => setNewEventDescription(e.target.value)}
                placeholder="Enter event description (optional)..."
                rows={2}
                className="w-full px-4 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary resize-none"
              />

              {/* Location Field */}
              <input
                type="text"
                value={eventLocation}
                onChange={(e) => setEventLocation(e.target.value)}
                placeholder="📍 Add location (optional)..."
                className="w-full px-4 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
              />

              {/* Time Picker */}
              <div className="space-y-2">
                <label className="flex items-center gap-2">
                  <input
                    type="checkbox"
                    checked={isAllDay}
                    onChange={(e) => setIsAllDay(e.target.checked)}
                    className="rounded"
                  />
                  <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">All-day event</span>
                </label>

                {!isAllDay && (
                  <div className="grid grid-cols-2 gap-2">
                    <div>
                      <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                        Start Time
                      </label>
                      <input
                        type="time"
                        value={startTime}
                        onChange={(e) => setStartTime(e.target.value)}
                        className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                      />
                    </div>
                    <div>
                      <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                        End Time
                      </label>
                      <input
                        type="time"
                        value={endTime}
                        onChange={(e) => setEndTime(e.target.value)}
                        className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-blue"
                      />
                    </div>
                  </div>
                )}
              </div>

              {/* Start Date */}
              <div>
                <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  Start Date
                </label>
                <input
                  type="date"
                  value={selectedDateKey}
                  onChange={(e) => setSelectedDateKey(e.target.value)}
                  className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                />
              </div>

              {/* Multi-day Event: End Date */}
              <div>
                <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  End Date (optional - for multi-day events)
                </label>
                <input
                  type="date"
                  value={eventEndDate}
                  onChange={(e) => setEventEndDate(e.target.value)}
                  min={selectedDateKey}
                  className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                  placeholder="Leave empty for single-day event"
                />
                {eventEndDate && (
                  <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                    Event will span from {selectedDateKey} to {eventEndDate}
                  </p>
                )}
              </div>

              {/* Recurrence Picker */}
              <div>
                <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  Repeat
                </label>
                <select
                  value={recurrenceType}
                  onChange={(e) => setRecurrenceType(e.target.value as 'none' | 'daily' | 'weekly' | 'monthly')}
                  className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                >
                  <option value="none">Does not repeat</option>
                  <option value="daily">Daily</option>
                  <option value="weekly">Weekly</option>
                  <option value="monthly">Monthly</option>
                </select>
              </div>

              {/* Weekly: Day Selection */}
              {recurrenceType === 'weekly' && (
                <div>
                  <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
                    Repeat on
                  </label>
                  <div className="grid grid-cols-7 gap-2">
                    {['S', 'M', 'T', 'W', 'T', 'F', 'S'].map((day, index) => {
                      const isSelected = weeklyDays.includes(index);
                      return (
                        <button
                          key={index}
                          type="button"
                          onClick={() => {
                            if (isSelected) {
                              setWeeklyDays(weeklyDays.filter((d) => d !== index));
                            } else {
                              setWeeklyDays([...weeklyDays, index].sort());
                            }
                          }}
                          className={`
                            w-8 h-8 rounded-full text-sm font-medium transition-all
                            ${isSelected
                              ? 'bg-accent-blue text-white'
                              : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:bg-accent-blue/20'
                            }
                          `}
                        >
                          {day}
                        </button>
                      );
                    })}
                  </div>
                </div>
              )}

              {/* Monthly: Day Selection */}
              {recurrenceType === 'monthly' && (
                <div>
                  <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                    Day of month
                  </label>
                  <input
                    type="number"
                    min="1"
                    max="31"
                    value={monthlyDay}
                    onChange={(e) => setMonthlyDay(Math.min(31, Math.max(1, parseInt(e.target.value) || 1)))}
                    className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                  />
                </div>
              )}

              {/* End Condition */}
              {recurrenceType !== 'none' && (
                <div>
                  <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-1">
                    Ends
                  </label>
                  <select
                    value={recurrenceEndType}
                    onChange={(e) => setRecurrenceEndType(e.target.value as 'never' | 'after' | 'until')}
                    className="w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                  >
                    <option value="never">Never</option>
                    <option value="after">After</option>
                    <option value="until">On date</option>
                  </select>

                  {recurrenceEndType === 'after' && (
                    <div className="mt-2 flex items-center gap-2">
                      <input
                        type="number"
                        min="1"
                        max="999"
                        value={recurrenceEndCount}
                        onChange={(e) => setRecurrenceEndCount(Math.max(1, parseInt(e.target.value) || 1))}
                        className="w-20 px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                      />
                      <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
                        occurrences
                      </span>
                    </div>
                  )}

                  {recurrenceEndType === 'until' && (
                    <input
                      type="date"
                      value={recurrenceEndDate}
                      onChange={(e) => setRecurrenceEndDate(e.target.value)}
                      className="mt-2 w-full px-3 py-2 border border-border-light dark:border-border-dark rounded-lg bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-primary"
                    />
                  )}
                </div>
              )}

              {/* Event Reminders */}
              <div>
                <label className="block text-sm text-text-light-secondary dark:text-text-dark-secondary mb-2">
                  Reminders
                </label>
                <div className="space-y-2">
                  {REMINDER_OPTIONS.map((option) => (
                    <label key={option.value} className="flex items-center gap-2 text-sm">
                      <input
                        type="checkbox"
                        checked={eventReminders.includes(option.value)}
                        onChange={(e) => {
                          if (e.target.checked) {
                            setEventReminders([...eventReminders, option.value].sort((a, b) => a - b));
                          } else {
                            setEventReminders(eventReminders.filter((r) => r !== option.value));
                          }
                        }}
                        className="rounded"
                      />
                      <span className="text-text-light-secondary dark:text-text-dark-secondary">
                        {option.label}
                      </span>
                    </label>
                  ))}
                </div>
                {eventReminders.length > 0 && (
                  <p className="text-xs text-accent-blue dark:text-accent-blue-hover mt-2">
                    {eventReminders.length} reminder{eventReminders.length > 1 ? 's' : ''} set
                  </p>
                )}
              </div>

              <div className="flex gap-2">
                <button
                  onClick={handleAddEvent}
                  className="flex-1 px-4 py-2 bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors"
                >
                  {editingEventId ? 'Update' : 'Add'}
                </button>
                {editingEventId && (
                  <button
                    onClick={handleCancelEdit}
                    className="px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded-lg hover:opacity-80 transition-opacity"
                  >
                    Cancel
                  </button>
                )}
              </div>
            </div>
          </div>

          {/* Close Button */}
          <div className="flex justify-end pt-2">
            <button
              onClick={() => setIsModalOpen(false)}
              className="px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-primary dark:text-text-dark-primary rounded-lg hover:opacity-80 transition-opacity"
            >
              Close
            </button>
          </div>
        </div>
      </Modal>

      {/* Recurring Event Dialog */}
      <RecurringEventDialog
        isOpen={isRecurringDialogOpen}
        onClose={() => {
          setIsRecurringDialogOpen(false);
          setPendingRecurringEvent(null);
        }}
        onThisEvent={recurringAction === 'edit' ? handleEditThisEvent : handleDeleteThisEvent}
        onAllEvents={recurringAction === 'edit' ? handleEditAllEvents : handleDeleteAllEvents}
        action={recurringAction}
        eventTitle={pendingRecurringEvent?.title || ''}
      />
    </Widget>
  );
};

// ==================== MONTH VIEW COMPONENT ====================

interface MonthViewProps {
  currentDate: Date;
  events: Record<string, CalendarEvent[]>;
  tasks: Task[];
  onDayClick: (dateKey: string) => void;
}

const MonthView: React.FC<MonthViewProps> = ({
  currentDate,
  events,
  tasks,
  onDayClick,
}) => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const firstDay = getFirstDayOfMonth(currentDate);
  const daysInMonth = getDaysInMonth(currentDate);
  const daysInPrevMonth = getDaysInPrevMonth(currentDate);

  const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];

  // Generate day cells
  const dayCells = useMemo(() => {
    const cells = [];

    // Previous month days
    for (let i = firstDay - 1; i >= 0; i--) {
      const dayNum = daysInPrevMonth - i;
      const date = new Date(year, month - 1, dayNum);
      cells.push({
        date,
        dayNum,
        isOtherMonth: true,
        isToday: false,
        dateKey: getStandardDateKey(date),
      });
    }

    // Current month days
    for (let i = 1; i <= daysInMonth; i++) {
      const date = new Date(year, month, i);
      const dateKey = getStandardDateKey(date);
      cells.push({
        date,
        dayNum: i,
        isOtherMonth: false,
        isToday: isToday(date),
        dateKey,
      });
    }

    // Next month days (to fill grid)
    const totalCells = cells.length;
    const remainingCells = 35 - totalCells;
    for (let i = 1; i <= remainingCells; i++) {
      const date = new Date(year, month + 1, i);
      cells.push({
        date,
        dayNum: i,
        isOtherMonth: true,
        isToday: false,
        dateKey: getStandardDateKey(date),
      });
    }

    return cells;
  }, [year, month, firstDay, daysInMonth, daysInPrevMonth]);

  // Filter tasks with date ranges (memoized to avoid re-filtering on every render)
  const tasksWithDates = useMemo(
    () => tasks.filter((task) => task.startDate && task.dueDate),
    [tasks]
  );

  return (
    <div className="calendar-month-view flex-1 grid grid-rows-[auto_1fr] gap-2">
      {/* Day headers */}
      <div className="grid grid-cols-7 gap-px">
        {days.map((day) => (
          <div
            key={day}
            className="calendar-day-header text-center font-semibold text-sm text-text-light-secondary dark:text-text-dark-secondary py-2"
          >
            {day}
          </div>
        ))}
      </div>

      {/* Day cells */}
      <div className="grid grid-cols-7 grid-rows-5 gap-px">
        {dayCells.map((cell, index) => {
          const hasEvent = (events[cell.dateKey]?.length || 0) > 0;

          return (
            <DayCell
              key={index}
              date={cell.date}
              dayNum={cell.dayNum}
              isOtherMonth={cell.isOtherMonth}
              isToday={cell.isToday}
              hasEvent={hasEvent}
              dateKey={cell.dateKey}
              tasks={tasksWithDates}
              events={events}
              onClick={() => !cell.isOtherMonth && onDayClick(cell.dateKey)}
            />
          );
        })}
      </div>
    </div>
  );
};

// ==================== DAY CELL COMPONENT ====================

interface DayCellProps {
  date: Date;
  dayNum: number;
  isOtherMonth: boolean;
  isToday: boolean;
  hasEvent: boolean;
  dateKey: string;
  tasks: Task[];
  events: Record<string, CalendarEvent[]>;
  onClick: () => void;
}

const DayCellComponent: React.FC<DayCellProps> = ({
  date,
  dayNum,
  isOtherMonth,
  isToday,
  hasEvent,
  dateKey,
  tasks,
  events,
  onClick,
}) => {
  // Find tasks that overlap this day
  const overlappingTasks = tasks.filter((task) => {
    const startDate = new Date(task.startDate!);
    const dueDate = new Date(task.dueDate!);
    return isDateBetween(date, startDate, dueDate);
  });

  const priorityColors = {
    low: 'bg-accent-cyan',
    medium: 'bg-status-warning',
    high: 'bg-status-error',
  };

  return (
    <div
      onClick={onClick}
      className={`
        calendar-day
        relative
        border rounded
        p-2
        min-h-[100px]
        cursor-pointer
        transition-all
        hover:shadow-md
        ${isOtherMonth ? 'bg-neutral-100 dark:bg-neutral-700 opacity-50' : 'bg-surface-light-elevated dark:bg-neutral-800'}
        ${isToday ? 'ring-2 ring-accent-cyan' : 'border-neutral-200 dark:border-neutral-700'}
        ${hasEvent ? 'border-accent-magenta' : ''}
      `}
    >
      {/* Day number */}
      <div
        className={`
          calendar-day-number
          text-sm font-semibold
          ${isToday ? 'text-accent-cyan' : 'text-text-light-secondary dark:text-text-dark-secondary'}
        `}
      >
        {dayNum}
      </div>

      {/* Event indicator dot */}
      {hasEvent && (
        <div className="absolute top-1 right-1 w-2 h-2 bg-accent-magenta rounded-full"></div>
      )}

      {/* Event bars (multi-day events shown as colored bars) */}
      {hasEvent && (
        <div className="mt-1 space-y-1">
          {events[dateKey].slice(0, 2).map((event) => {
            const isMultiDay = event._isMultiDayPart;
            const isFirst = event._isMultiDayFirst;
            const isLast = event._isMultiDayLast;

            return (
              <div
                key={event.id}
                className={`
                  text-xs
                  px-1
                  py-0.5
                  text-white
                  font-medium
                  truncate
                  bg-accent-magenta
                  ${isMultiDay ? (isFirst ? 'rounded-l' : isLast ? 'rounded-r' : '') : 'rounded'}
                `}
                title={event.title}
              >
                {event.title}
              </div>
            );
          })}
          {events[dateKey].length > 2 && (
            <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary px-1">
              +{events[dateKey].length - 2} more
            </div>
          )}
        </div>
      )}

      {/* Task bars */}
      <div className="mt-1 space-y-1">
        {overlappingTasks.slice(0, 2).map((task) => (
          <div
            key={task.id}
            className={`
              calendar-task-bar
              text-xs
              px-1
              py-0.5
              rounded
              text-white
              truncate
              ${priorityColors[task.priority || 'medium']}
            `}
            title={task.title}
          >
            {task.title}
          </div>
        ))}
        {overlappingTasks.length > 2 && (
          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
            +{overlappingTasks.length - 2} more
          </div>
        )}
      </div>
    </div>
  );
};

// Memoize DayCell to prevent unnecessary re-renders (35 cells per month view)
const DayCell = React.memo(DayCellComponent, (prevProps, nextProps) => {
  return (
    prevProps.dayNum === nextProps.dayNum &&
    prevProps.isOtherMonth === nextProps.isOtherMonth &&
    prevProps.isToday === nextProps.isToday &&
    prevProps.hasEvent === nextProps.hasEvent &&
    prevProps.dateKey === nextProps.dateKey &&
    prevProps.tasks.length === nextProps.tasks.length
  );
});

