     1→import React, { useMemo } from 'react';
     2→import type { CalendarEvent } from '../types';
     3→import { format, parse, isAfter, addDays, startOfDay, isSameDay } from 'date-fns';
     4→
     5→interface AgendaViewProps {
     6→  events: Record<string, CalendarEvent[]>; // Expanded events (including recurring instances)
     7→  currentDate?: Date; // Optional - not used in current implementation
     8→  daysToShow?: number; // Number of days to display (default: 14)
     9→  onEventClick?: (event: CalendarEvent, dateKey: string) => void;
    10→}
    11→
    12→/**
    13→ * AgendaView Component
    14→ * Displays upcoming events in a list format, grouped by day
    15→ */
    16→export const AgendaView: React.FC<AgendaViewProps> = ({
    17→  events,
    18→  onEventClick,
    19→}) => {
    20→  // Calculate all events (sorted by date)
    21→  const upcomingEvents = useMemo(() => {
    22→    const today = startOfDay(new Date());
    23→
    24→    // Group all events by date
    25→    const grouped: { date: Date; dateKey: string; events: CalendarEvent[] }[] = [];
    26→
    27→    Object.entries(events).forEach(([dateKey, dayEvents]) => {
    28→      const eventDate = parse(dateKey, 'yyyy-MM-dd', new Date());
    29→
    30→      // Only include events from today onwards
    31→      if (isAfter(eventDate, today) || isSameDay(eventDate, today)) {
    32→        grouped.push({
    33→          date: eventDate,
    34→          dateKey,
    35→          events: dayEvents,
    36→        });
    37→      }
    38→    });
    39→
    40→    // Sort by date (ascending)
    41→    grouped.sort((a, b) => a.date.getTime() - b.date.getTime());
    42→
    43→    return grouped;
    44→  }, [events]);
    45→
    46→  const formatEventTime = (event: CalendarEvent): string => {
    47→    if (event.isAllDay || !event.startTime) {
    48→      return 'All day';
    49→    }
    50→
    51→    if (event.endTime) {
    52→      return `${event.startTime} - ${event.endTime}`;
    53→    }
    54→
    55→    return event.startTime;
    56→  };
    57→
    58→  const getDayLabel = (date: Date): string => {
    59→    const today = startOfDay(new Date());
    60→    const tomorrow = addDays(today, 1);
    61→
    62→    if (isSameDay(date, today)) {
    63→      return 'Today';
    64→    }
    65→
    66→    if (isSameDay(date, tomorrow)) {
    67→      return 'Tomorrow';
    68→    }
    69→
    70→    return format(date, 'EEEE');
    71→  };
    72→
    73→  if (upcomingEvents.length === 0) {
    74→    return (
    75→      <div className="flex flex-col items-center justify-center py-16 px-4 text-center">
    76→        <div className="text-6xl mb-4">📅</div>
    77→        <h3 className="text-lg font-medium text-text-light-primary dark:text-text-dark-primary mb-2">
    78→          No upcoming events
    79→        </h3>
    80→        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary max-w-md">
    81→          You don't have any events scheduled. Add an event to get started!
    82→        </p>
    83→      </div>
    84→    );
    85→  }
    86→
    87→  return (
    88→    <div className="h-full flex flex-col">
    89→      {/* Frozen header */}
    90→      <div className="flex-shrink-0 bg-surface-light dark:bg-surface-dark border-b border-border-light dark:border-border-dark p-4">
    91→        <h2 className="text-xl font-bold text-text-light-primary dark:text-text-dark-primary">
    92→          Upcoming Events
    93→        </h2>
    94→        <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
    95→          {upcomingEvents.reduce((total, day) => total + day.events.length, 0)} total events
    96→        </p>
    97→      </div>
    98→
    99→      {/* Scrollable events list */}
   100→      <div className="flex-1 overflow-y-auto">
   101→        <div className="agenda-view space-y-6 p-4">
   102→          {upcomingEvents.map(({ date, dateKey, events: dayEvents }) => (
   103→            <div key={dateKey} className="agenda-day">
   104→              {/* Day Header */}
   105→              <div className="sticky top-0 z-10 bg-surface-light dark:bg-surface-dark border-b border-border-light dark:border-border-dark pb-2 mb-3">
   106→                <div className="flex items-baseline gap-3">
   107→                  <h3 className="text-lg font-semibold text-text-light-primary dark:text-text-dark-primary">
   108→                    {getDayLabel(date)}
   109→                  </h3>
   110→                  <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
   111→                    {format(date, 'MMMM d, yyyy')}
   112→                  </span>
   113→                  <span className="ml-auto text-xs text-text-light-secondary dark:text-text-dark-secondary">
   114→                    {dayEvents.length} event{dayEvents.length > 1 ? 's' : ''}
   115→                  </span>
   116→                </div>
   117→              </div>
   118→
   119→              {/* Events List */}
   120→              <div className="space-y-2">
   121→                {dayEvents.map((event) => (
   122→                  <div
   123→                    key={event.id}
   124→                    onClick={() => onEventClick?.(event, dateKey)}
   125→                    className={`
   126→                      p-4 rounded-lg border border-border-light dark:border-border-dark
   127→                      bg-surface-light-elevated dark:bg-surface-dark-elevated
   128→                      ${onEventClick ? 'cursor-pointer hover:shadow-medium hover:border-accent-cyan dark:hover:border-accent-cyan' : ''}
   129→                      transition-all duration-200
   130→                    `}
   131→                  >
   132→                    <div className="flex items-start gap-3">
   133→                      {/* Time */}
   134→                      <div className="flex-shrink-0 w-24 text-right">
   135→                        <div className="text-sm font-medium text-accent-cyan dark:text-accent-cyan-hover">
   136→                          {formatEventTime(event)}
   137→                        </div>
